import{_ as n,C as i,o as t,c as s,a5 as a,b as c,w as o,a as h,E as d,a6 as l}from"./chunks/framework.DsV6Qlrj.js";const z=JSON.parse('{"title":"Identity and authorization","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/identity-and-authorization.md","filePath":"concepts/identity-and-authorization.md"}'),u={name:"concepts/identity-and-authorization.md"};function p(m,e,f,b,A,k){const r=i("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="identity-and-authorization" tabindex="-1">Identity and authorization <a class="header-anchor" href="#identity-and-authorization" aria-label="Permalink to &quot;Identity and authorization&quot;">​</a></h1><p>Platform Mesh separates authentication, authorization data, and control-plane enforcement across several runtime components.</p><p>Use this page to understand the conceptual relationship. Use Reference only for concrete component and resource lookup.</p><h2 id="runtime-roles" tabindex="-1">Runtime roles <a class="header-anchor" href="#runtime-roles" aria-label="Permalink to &quot;Runtime roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Platform Mesh role</th></tr></thead><tbody><tr><td>Authentication</td><td>Keycloak is the default identity provider used by the local setup.</td></tr><tr><td>Authorization data</td><td>The OpenFGA engine holds one <em>IAM store</em> per organization or account, declared by a <a href="/main/reference/resources/iamstore-resource.html"><code>Store</code> CR</a>. Each IAM store carries the relationship-based authorization data for that account and its provider-consumer relationships.</td></tr><tr><td>Enforcement</td><td>rebac-authz-webhook participates in kcp authorization decisions.</td></tr><tr><td>Account lifecycle</td><td>Platform Mesh automation wires identity and authorization state as accounts and organizations are created.</td></tr></tbody></table><h2 id="runtime-relationship" tabindex="-1">Runtime relationship <a class="header-anchor" href="#runtime-relationship" aria-label="Permalink to &quot;Runtime relationship&quot;">​</a></h2>',6)),(t(),c(l,null,{default:o(()=>[d(r,{id:"mermaid-61",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Account%5B%22Account%20or%20organization%22%5D%0A%20%20%20%20Store%5B%22IAM%20store%3Cbr%3EOpenFGA%22%5D%0A%20%20%20%20Webhook%5B%22rebac-authz-webhook%22%5D%0A%20%20%20%20Kcp%5B%22kcp%20authorizer%20chain%22%5D%0A%0A%20%20%20%20Account%20--%3E%20Store%0A%20%20%20%20Store%20--%3E%20Webhook%0A%20%20%20%20Webhook%20--%3E%20Kcp%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[h(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p>Missing or stale authorization data can surface as authorization failures in kcp, the Kubernetes GraphQL gateway, or the portal.</p><h2 id="authorizer-chain" tabindex="-1">Authorizer chain <a class="header-anchor" href="#authorizer-chain" aria-label="Permalink to &quot;Authorizer chain&quot;">​</a></h2><p>Every API request that reaches kcp passes through this chain in order. When a request is denied, the deny comes from one of these stages:</p><ul><li><strong>Front proxy</strong> — terminates TLS and validates the request&#39;s identity against the OIDC issuer (Keycloak). A request without a valid token never reaches the authorizers.</li><li><strong>kcp built-in chain</strong> — RBAC, required-groups, workspace-content, and maximal-permission-policy authorizers run in order. Standard Kubernetes RBAC denials happen here.</li><li><strong>rebac-authz-webhook</strong> — the last stage. kcp sends a <code>SubjectAccessReview</code> to the webhook, which translates it into a <a href="https://openfga.dev/docs/getting-started/perform-check" target="_blank" rel="noreferrer">Check</a> against the consumer account&#39;s OpenFGA store and returns allow or deny. This is where Platform Mesh&#39;s relationship-based decisions land.</li></ul><p>If every stage returns &quot;no opinion&quot;, the request is denied by default. The webhook is configured with <code>failurePolicy: NoOpinion</code> so an unreachable webhook does not unilaterally allow traffic.</p><p>For the actual <code>AuthorizationConfiguration</code> YAML, the webhook deployment args, and per-workspace OIDC, see <a href="/main/reference/components/kcp/identity-and-authorization.html">Identity and authorization reference</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/main/concepts/security/">Security architecture</a> — design view: separation of concerns, OIDC federation, ReBAC, account-model integration</li><li><a href="./account-model.html">Account model</a></li><li><a href="/main/reference/resources/iamstore-resource.html">IAM Store resource</a></li><li><a href="/main/reference/components/keycloak.html">Keycloak</a></li><li><a href="/main/reference/components/openfga.html">OpenFGA</a></li><li><a href="/main/reference/components/rebac-authz-webhook.html">rebac-authz-webhook</a></li><li><a href="/main/reference/components/security-operator.html">Security operator</a></li></ul>',8))])}const g=n(u,[["render",p]]);export{z as __pageData,g as default};
